                {
                    // open and store the keyspace
                    keyspaceInstance = new Keyspace(keyspaceName, schema, loadSSTables);
                    schema.storeKeyspaceInstance(keyspaceInstance);
                }
            }
        }
        return keyspaceInstance;
    }

